const t={klipperscreenStudio:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Безопасно редактируйте конфигурацию сенсорного экрана KlipperScreen вашего принтера и перезапускайте KlipperScreen для применения. Перед каждым сохранением создаётся резервная копия."}},help:{title:{t:0,b:{t:2,i:[{t:3}],s:"Как это работает"}},body:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen.conf управляет сенсорным экраном, подключённым к принтеру — тема, язык, меню и параметры отображения. Этот редактор читает и пишет файл тем же безопасным путём, что и Редактор конфигурации."}},step1:{t:0,b:{t:2,i:[{t:3}],s:"Отредактируйте текст конфигурации ниже (или оставьте как есть)."}},step2:{t:0,b:{t:2,i:[{t:3}],s:"Сохраните — файл сначала резервируется, а сохранение отклоняется, пока принтер занят."}},step3:{t:0,b:{t:2,i:[{t:3}],s:"Перезапустите KlipperScreen, чтобы применить изменение на физическом экране."}},lfNote:{t:0,b:{t:2,i:[{t:3}],s:"Строки используют окончания UNIX (LF), применяемые автоматически при сохранении."}},topics:{glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Глоссарий"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Краткие определения терминов KlipperScreen, используемых здесь."}}},config:{title:{t:0,b:{t:2,i:[{t:3}],s:"Что за вкладка «Конфиг»?"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Это сам файл KlipperScreen.conf. Редактируйте любой параметр вручную; перед сохранением файл сначала резервируется, сохранение отклоняется, пока принтер занят, и предупреждает, если файл изменился на экране с момента загрузки. Большинство пользователей вместо этого работают на вкладках «Опции» / «Меню» / «Темы»."}}},settings:{title:{t:0,b:{t:2,i:[{t:3}],s:"Что за вкладка «Опции»?"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Самые используемые опции из [main] в виде формы — тема, язык, гашение экрана, размер шрифта и переключатели. Поля заполнены из текущей конфигурации; записываются только те опции, которые вы изменили. Перезапустите для применения."}}},menus:{title:{t:0,b:{t:2,i:[{t:3}],s:"Что за вкладка «Меню»?"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Проектируйте сетки кнопок сенсорного экрана. Каждое дерево (__main — это главная сетка, __print — экран печати) перечисляет свои кнопки; добавляйте, переименовывайте, меняйте порядок и вкладывайте их, и задавайте каждой действие: открыть подменю, открыть встроенный экран или выполнить G-code."}}},themes:{title:{t:0,b:{t:2,i:[{t:3}],s:"Что за вкладка «Темы»?"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Создайте тему KlipperScreen: выберите цвет для каждого токена палитры и радиус углов, наблюдайте за живым предпросмотром, затем создайте её и примените на экране. Предпросмотр приблизительный — реальный экран рисуется в GTK."}}},kiosk:{title:{t:0,b:{t:2,i:[{t:3}],s:"Что за вкладка «Киоск»?"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Выведите сам FilaMind Flow на сенсорный экран как полноэкранный браузер — полный контроль над тем, что показывает экран. Это обратимая замена KlipperScreen (по умолчанию временная; перезагрузка возвращает KlipperScreen). Требуется однократная установка на хосте принтера."}}}},glossary:{klipperScreen:{term:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Интерфейс сенсорного экрана, работающий на небольшом дисплее, подключённом к принтеру — отдельно от этой веб-панели."}}},theme:{term:{t:0,b:{t:2,i:[{t:3}],s:"Тема"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Внешний вид KlipperScreen — цвета, значки и радиус углов. Хранится в папке styles/<name> на хосте; только косметика (компоновку изменить нельзя)."}}},menu:{term:{t:0,b:{t:2,i:[{t:3}],s:"Меню (__main / __print)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Сетки кнопок, которые показывает KlipperScreen. __main — главный экран, __print — экран, показываемый во время печати, __splashscreen — экран запуска."}}},panel:{term:{t:0,b:{t:2,i:[{t:3}],s:"Экран"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Встроенный экран KlipperScreen, который может открыть кнопка (перемещение, температура, экструзия, карта стола, …). Их внутреннее содержимое задано KlipperScreen."}}},autoBlock:{term:{t:0,b:{t:2,i:[{t:3}],s:"Автоматически создаваемый блок (#~#)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Секция, которую KlipperScreen пишет для себя внизу конфига, после маркера #~#. FilaMind никогда её не редактирует — только ваши настройки выше неё."}}},kiosk:{term:{t:0,b:{t:2,i:[{t:3}],s:"Киоск"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Запуск полноэкранного браузера на сенсорном экране вместо KlipperScreen, чтобы экран показывал FilaMind Flow. Полностью обратимо."}}}}},status:{checking:{t:0,b:{t:2,i:[{t:3}],s:"Поиск KlipperScreen…"}},absent:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen не обнаружен на этом принтере (нет KlipperScreen.conf, и не сообщён Moonraker). Установите KlipperScreen, чтобы использовать этот инструмент."}},present:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen обнаружен"}},theme:{t:0,b:{t:2,i:[{t:3}],s:"Тема"}},language:{t:0,b:{t:2,i:[{t:3}],s:"Язык"}},notRestartable:{t:0,b:{t:2,i:[{t:3}],s:"Moonraker не может перезапустить KlipperScreen автоматически — перезапустите его вручную после сохранения."}}},editor:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Чтение KlipperScreen.conf…"}},reload:{t:0,b:{t:2,i:[{t:3}],s:"Перезагрузить"}},save:{t:0,b:{t:2,i:[{t:3}],s:"Сохранить конфиг"}},saving:{t:0,b:{t:2,i:[{t:3}],s:"Сохранение…"}},saved:{t:0,b:{t:2,i:[{t:3}],s:"Сохранено (с резервной копией)"}},unsaved:{t:0,b:{t:2,i:[{t:3}],s:"Несохранённые изменения"}}},save:{busy:{t:0,b:{t:2,i:[{t:3}],s:"Отклонено, пока принтер занят — повторите, когда он свободен."}},stale:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen.conf изменился на диске с момента загрузки (вероятно, отредактирован на экране). Перезагрузите перед сохранением, чтобы не перезаписать это изменение."}}},view:{config:{t:0,b:{t:2,i:[{t:3}],s:"Конфиг"}},settings:{t:0,b:{t:2,i:[{t:3}],s:"Опции"}},menus:{t:0,b:{t:2,i:[{t:3}],s:"Меню"}},themes:{t:0,b:{t:2,i:[{t:3}],s:"Темы"}},kiosk:{t:0,b:{t:2,i:[{t:3}],s:"Киоск"}}},settings:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Загрузка опций…"}},intro:{t:0,b:{t:2,i:[{t:3}],s:"Самые используемые опции экрана KlipperScreen в виде формы. Записывается только то, что вы изменили — остальное сохраняет своё значение. Перезапустите для применения."}},onlyChanged:{t:0,b:{t:2,i:[{t:3}],s:"В KlipperScreen.conf записываются только изменённые здесь опции."}},save:{t:0,b:{t:2,i:[{t:3}],s:"Сохранить опции"}},savedRestart:{t:0,b:{t:2,i:[{t:3}],s:"Сохранено — перезапустите KlipperScreen для применения."}},unset:{t:0,b:{t:2,i:[{t:3}],s:"Не задавать (по умолчанию)"}},never:{t:0,b:{t:2,i:[{t:3}],s:"Никогда (всегда включён)"}},fontSize:{small:{t:0,b:{t:2,i:[{t:3}],s:"Мелкий"}},medium:{t:0,b:{t:2,i:[{t:3}],s:"Средний"}},large:{t:0,b:{t:2,i:[{t:3}],s:"Крупный"}},max:{t:0,b:{t:2,i:[{t:3}],s:"Макс."}}},label:{theme:{t:0,b:{t:2,i:[{t:3}],s:"Тема"}},language:{t:0,b:{t:2,i:[{t:3}],s:"Язык"}},screen_blanking:{t:0,b:{t:2,i:[{t:3}],s:"Гасить экран через"}},font_size:{t:0,b:{t:2,i:[{t:3}],s:"Размер шрифта"}},"24htime":{t:0,b:{t:2,i:[{t:3}],s:"24-часовой формат"}},use_dpms:{t:0,b:{t:2,i:[{t:3}],s:"Использовать DPMS для гашения экрана"}},show_cursor:{t:0,b:{t:2,i:[{t:3}],s:"Показывать курсор мыши"}},confirm_estop:{t:0,b:{t:2,i:[{t:3}],s:"Подтверждать аварийный стоп"}},show_heater_power:{t:0,b:{t:2,i:[{t:3}],s:"Показывать мощность нагревателя %"}},autoclose_popups:{t:0,b:{t:2,i:[{t:3}],s:"Автозакрытие всплывающих окон"}}}},kiosk:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Проверка экрана…"}},intro:{t:0,b:{t:2,i:[{t:3}],s:"Выведите сам FilaMind Flow на сенсорный экран как полноэкранный браузер — полный контроль над тем, что показывает экран. Он меняется с KlipperScreen: запуск одного останавливает другой."}},current:{t:0,b:{t:2,i:[{t:3}],s:"Экран сейчас"}},mode:{kiosk:{t:0,b:{t:2,i:[{t:3}],s:"Киоск FilaMind"}},klipperscreen:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen"}},none:{t:0,b:{t:2,i:[{t:3}],s:"Ничего не запущено"}}},notInstalled:{t:0,b:{t:2,i:[{t:3}],s:"Киоск ещё не установлен"}},setupHint:{t:0,b:{t:2,i:[{t:3}],s:"Выполните это один раз на хосте принтера (ставит полноэкранный браузер + службу киоска):"}},persist:{t:0,b:{t:2,i:[{t:3}],s:"Сделать по умолчанию при загрузке (иначе переключение временное — перезагрузка вернёт другой)."}},safety:{t:0,b:{t:2,i:[{t:3}],s:"По умолчанию временно: перезагрузка вернёт другой. Если экран погас, по SSH: sudo systemctl start KlipperScreen"}},switchBtn:{t:0,b:{t:2,i:[{t:3}],s:"Переключить на FilaMind"}},restoreBtn:{t:0,b:{t:2,i:[{t:3}],s:"Вернуть KlipperScreen"}},refresh:{t:0,b:{t:2,i:[{t:3}],s:"Обновить"}},confirmSwitchTitle:{t:0,b:{t:2,i:[{t:3}],s:"Вывести FilaMind на экран?"}},confirmRestoreTitle:{t:0,b:{t:2,i:[{t:3}],s:"Вернуть KlipperScreen?"}},confirmBody:{t:0,b:{t:2,i:[{t:3}],s:"Это остановит одну службу экрана и запустит другую. На активную печать не влияет, но сенсорный экран погаснет на несколько секунд при переключении."}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Выполнить"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Отмена"}},switchedNote:{t:0,b:{t:2,i:[{t:3}],s:"FilaMind занимает экран — появится через несколько секунд."}},restoredNote:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen возвращается — экран скоро вернётся."}}},menus:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Загрузка меню…"}},intro:{t:0,b:{t:2,i:[{t:3}],s:"Спроектируйте, что показывает сенсорный экран: кнопки каждого меню, их порядок и действие каждой. Сетка главного экрана — дерево __main, экран печати — __print."}},addItem:{t:0,b:{t:2,i:[{t:3}],s:"Добавить кнопку"}},empty:{t:0,b:{t:2,i:[{t:3}],s:"Пока нет элементов — добавьте."}},up:{t:0,b:{t:2,i:[{t:3}],s:"Вверх"}},down:{t:0,b:{t:2,i:[{t:3}],s:"Вниз"}},addChild:{t:0,b:{t:2,i:[{t:3}],s:"Добавить подпункт"}},delete:{t:0,b:{t:2,i:[{t:3}],s:"Удалить"}},name:{t:0,b:{t:2,i:[{t:3}],s:"Имя"}},icon:{t:0,b:{t:2,i:[{t:3}],s:"Значок"}},action:{t:0,b:{t:2,i:[{t:3}],s:"Действие"}},actSubmenu:{t:0,b:{t:2,i:[{t:3}],s:"Открыть подменю"}},actPanel:{t:0,b:{t:2,i:[{t:3}],s:"Открыть экран"}},actGcode:{t:0,b:{t:2,i:[{t:3}],s:"Выполнить G-code"}},panel:{t:0,b:{t:2,i:[{t:3}],s:"Экран"}},gcode:{t:0,b:{t:2,i:[{t:3}],s:"G-code"}},enable:{t:0,b:{t:2,i:[{t:3}],s:"Показывать если"}},save:{t:0,b:{t:2,i:[{t:3}],s:"Сохранить меню"}},newItem:{t:0,b:{t:2,i:[{t:3}],s:"Новая кнопка"}},savedRestart:{t:0,b:{t:2,i:[{t:3}],s:"Меню сохранены — перезапустите KlipperScreen, чтобы увидеть."}}},themes:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Загрузка тем…"}},palette:{t:0,b:{t:2,i:[{t:3}],s:"Палитра"}},radius:{t:0,b:{t:2,i:[{t:3}],s:"Радиус углов"}},preview:{t:0,b:{t:2,i:[{t:3}],s:"Живой предпросмотр"}},btn:{t:0,b:{t:2,i:[{t:3}],s:"Кнопка"}},previewWarn:{t:0,b:{t:2,i:[{t:3}],s:"предупреждение"}},previewApprox:{t:0,b:{t:2,i:[{t:3}],s:"Приблизительный предпросмотр — реальный экран рисуется в GTK; небольшие отличия ожидаемы."}},namePlaceholder:{t:0,b:{t:2,i:[{t:3}],s:"Имя новой темы"}},createApply:{t:0,b:{t:2,i:[{t:3}],s:"Создать и применить"}},createOnly:{t:0,b:{t:2,i:[{t:3}],s:"Только создать"}},installed:{t:0,b:{t:2,i:[{t:3}],s:"Установленные темы"}},apply:{t:0,b:{t:2,i:[{t:3}],s:"Применить"}},delete:{t:0,b:{t:2,i:[{t:3}],s:"Удалить тему"}},generated:{t:0,b:{t:2,i:[{t:3}],s:"Создано здесь"}},created:{t:0,b:{t:2,i:[{t:3}],s:"Тема создана. Примените её из списка, затем перезапустите."}},appliedRestart:{t:0,b:{t:2,i:[{t:3}],s:"Тема выбрана — перезапустите KlipperScreen, чтобы увидеть её."}}},restart:{button:{t:0,b:{t:2,i:[{t:3}],s:"Перезапустить KlipperScreen"}},restarting:{t:0,b:{t:2,i:[{t:3}],s:"Перезапуск…"}},done:{t:0,b:{t:2,i:[{t:3}],s:"KlipperScreen перезапускается — экран скоро обновится."}},confirmTitle:{t:0,b:{t:2,i:[{t:3}],s:"Перезапустить KlipperScreen?"}},confirmBody:{t:0,b:{t:2,i:[{t:3}],s:"Это перезапустит службу сенсорного экрана для применения изменений. Это не повлияет на активную печать, но экран погаснет на несколько секунд."}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Перезапустить"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Отмена"}}}}};export{t as default};
